import React from "react";

const capabilities = [
  {
    tag: "Agentic Systems",
    title: "End-to-end AI agents",
    body:
      "Built ARIA — a fully local agentic AI assistant — and an ABM agent that moves leads from Apollo through HubSpot automatically. These aren't demos; they run in production.",
  },
  {
    tag: "LLM Evaluation",
    title: "LLM-as-judge frameworks",
    body:
      "Designed evaluation pipelines that use language models to grade language model output. Structured, reproducible, and honest about what the model gets wrong.",
  },
  {
    tag: "MCP Architecture",
    title: "MCP-based agent design",
    body:
      "Built multi-agent architectures using the Model Context Protocol. Agents that use tools, call each other, and handle failure gracefully.",
  },
  {
    tag: "Automation",
    title: "Real automation pipelines",
    body:
      "n8n, Make, Zapier — orchestrating APIs, transforming data, and shipping workflows that replace manual work. Connected to HubSpot, Apollo, Microsoft 365, and more.",
  },
  {
    tag: "AI Content Systems",
    title: "AI-powered content at scale",
    body:
      "Weekly AI digest built on Google Apps Script + Gemini API. Content that goes out automatically, on schedule, every week.",
  },
  {
    tag: "Stack",
    title: "Tools I work in",
    body:
      "Claude, Claude Code, ChatGPT, OpenAI APIs, n8n, Make, Zapier, MCP, GitHub, HubSpot API, Apollo API, Microsoft 365, Copilot — and counting.",
  },
];

const honestGaps = [
  "Not a traditional software engineer",
  "Python at automation level, not production engineering",
  "No RAG or vector DB experience yet",
];

export default function WhatIBuild() {
  return (
    <section
      id="builds"
      className="section"
      style={{
        paddingLeft: "clamp(1.5rem, 8vw, 8rem)",
        paddingRight: "clamp(1.5rem, 8vw, 8rem)",
        borderTop: "1px solid #2C2C3E"
      }}
    >
      {/* Header */}
      <div className="mb-16" style={{ maxWidth: "48ch" }}>
        <p className="eyebrow mb-4">What I Build</p>
        <h2
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(1.8rem, 4vw, 2.8rem)",
            fontWeight: 700,
            letterSpacing: "-0.025em",
            color: "#F0F0EC",
            lineHeight: 1.1
          }}
        >
          An AI engineering profile, in plain language.
        </h2>
        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "1rem",
            color: "#8A8A9A",
            marginTop: "1rem",
            lineHeight: 1.7
          }}
        >
          Two years building production AI systems without a traditional software
          background. Here's what that actually looks like.
        </p>
      </div>

      {/* Capabilities grid */}
      <div
        className="grid gap-5"
        style={{
          gridTemplateColumns: "repeat(auto-fill, minmax(min(100%, 320px), 1fr))"
        }}
      >
        {capabilities.map((cap) => (
          <div
            key={cap.tag}
            className="card"
            style={{ padding: "1.75rem" }}
          >
            <p
              className="eyebrow"
              style={{ marginBottom: "0.75rem" }}
            >
              {cap.tag}
            </p>
            <h3
              style={{
                fontFamily: "'Space Grotesk', sans-serif",
                fontWeight: 600,
                fontSize: "1.05rem",
                color: "#F0F0EC",
                marginBottom: "0.6rem",
                letterSpacing: "-0.01em"
              }}
            >
              {cap.title}
            </h3>
            <p
              style={{
                fontFamily: "'Inter', sans-serif",
                fontSize: "0.9rem",
                color: "#8A8A9A",
                lineHeight: 1.65
              }}
            >
              {cap.body}
            </p>
          </div>
        ))}
      </div>

      {/* Honest gaps */}
      <div
        className="card mt-10"
        style={{
          padding: "1.75rem 2rem",
          borderColor: "#2C2C3E",
          display: "flex",
          flexDirection: "column",
          gap: "1rem"
        }}
      >
        <p className="eyebrow" style={{ color: "#8A8A9A" }}>
          Honest gaps — because every builder has them
        </p>
        <ul
          style={{
            display: "flex",
            flexWrap: "wrap",
            gap: "0.6rem",
            listStyle: "none"
          }}
        >
          {honestGaps.map((gap) => (
            <li
              key={gap}
              style={{
                fontFamily: "'JetBrains Mono', monospace",
                fontSize: "0.75rem",
                color: "#8A8A9A",
                background: "#0A0A0F",
                border: "1px solid #2C2C3E",
                borderRadius: "0.25rem",
                padding: "0.35rem 0.75rem"
              }}
            >
              {gap}
            </li>
          ))}
        </ul>
        <p
          style={{
            fontFamily: "'Inter', sans-serif",
            fontSize: "0.85rem",
            color: "#4A4A5E"
          }}
        >
          Transparency is part of good systems thinking.
        </p>
      </div>
    </section>
  );
}
